function transform (message, context) {
  // Put your code here.
  const bannerId = context.get('bannerId');
  const termCode = context.get('termCode');
  const crn = context.get('crn');

  message.payload.bannerId = bannerId;
  message.payload.termCode = termCode;
  message.payload.crn = crn;

  return message;
}

function transform (message, context) {
  // Put your code here.
  let resStudentAcademicDetails = message.payload.resStudentAcademicDetails;
  if (resStudentAcademicDetails.length == 0){
    return {
      attemptedCreditHours: "N/A",
      earnedCreditHours: "N/A",
      grade: "N/A",
      gradeMode: "N/A"
    }
  }

  resStudentAcademicDetails = resStudentAcademicDetails?.[0]
  const grade = resStudentAcademicDetails.grades?.[0]

  return {
    attemptedCreditHours: grade.attemptedHours,
    earnedCreditHours: grade.creditHours,
    grade: grade.grade,
    gradeMode: grade.mode,
    gradeModeDescription: grade.modeDescription
  }

}
